### 8. 코드 예시: 즉시 개선 방안

#### Before (복잡한 의존성)
```kotlin
@Service
class CallService(
    private val callRepository: CallRepository,
    private val userRepository: UserRepository,
    private val notificationService: NotificationService,
    private val auditService: AuditService,
    private val analyticsService: AnalyticsService,
    private val paymentService: PaymentService,
    private val cacheService: CacheService,
    private val blockService: BlockService
) {
    @Transactional
    fun initiateCall(callerId: Long, calleeId: Long): Call {
        // 1. 검증
        val caller = userRepository.findById(callerId) ?: throw UserNotFound()
        val callee = userRepository.findById(calleeId) ?: throw UserNotFound()
        if (blockService.isBlocked(caller, callee)) throw UserBlocked()

        // 2. Call 생성
        val call = Call(caller, callee, LocalDateTime.now())
        callRepository.save(call)

        // 3. 캐싱
        cacheService.set("call:${call.id}", call, Duration.ofMinutes(30))

        // 4. 알림
        notificationService.notifyIncomingCall(callee, call)

        // 5. 감사
        auditService.logCallInitiation(caller, callee)

        // 6. 분석
        analyticsService.trackCallStart(caller, callee)

        // 7. 결제 초기화
        paymentService.initializeCallBilling(call)

        return call
    }
}
```

#### After (분리된 책임)
```kotlin
// 1. 핵심 서비스 (단일 책임)
@Service
class CallCoreService(
    private val callRepository: CallRepository
) {
    @Transactional
    fun initiateCall(caller: User, callee: User): Call {
        val call = Call(caller, callee, LocalDateTime.now())
        return callRepository.save(call)
    }
}

// 2. 검증 서비스
@Service
class CallValidationService(
    private val userRepository: UserRepository,
    private val blockService: BlockService
) {
    fun validateCallInitiation(callerId: Long, calleeId: Long) {
        val caller = userRepository.findById(callerId) ?: throw UserNotFound()
        val callee = userRepository.findById(calleeId) ?: throw UserNotFound()
        if (blockService.isBlocked(caller, callee)) throw UserBlocked()
    }
}

// 3. 외부 서비스 어댑터
@Service
class CallExternalServiceAdapter(
    private val notificationService: NotificationService,
    private val paymentService: PaymentService,
    private val cacheService: CacheService
) {
    fun notifyIncomingCall(call: Call) {
        notificationService.notifyIncomingCall(call.callee, call)
    }

    fun initializeBilling(call: Call) {
        paymentService.initializeCallBilling(call)
    }

    fun cacheCall(call: Call) {
        cacheService.set("call:${call.id}", call, Duration.ofMinutes(30))
    }
}

// 4. 이벤트 발행
@Component
class CallEventPublisher(
    private val applicationEventPublisher: ApplicationEventPublisher
) {
    fun publishCallInitiated(call: Call) {
        applicationEventPublisher.publishEvent(CallInitiatedEvent(call))
    }
}

// 5. 감사 및 분석은 Event Listener로
@Component
class CallAuditListener {
    @EventListener
    fun onCallInitiated(event: CallInitiatedEvent) {
        auditService.logCallInitiation(event.call.caller, event.call.callee)
    }
}

@Component
class CallAnalyticsListener {
    @EventListener
    fun onCallInitiated(event: CallInitiatedEvent) {
        analyticsService.trackCallStart(event.call.caller, event.call.callee)
    }
}

// 6. Orchestrator
@Service
class CallOrchestrationService(
    private val coreService: CallCoreService,
    private val validationService: CallValidationService,
    private val externalAdapter: CallExternalServiceAdapter,
    private val eventPublisher: CallEventPublisher
) {
    @Transactional
    fun initiateCall(callerId: Long, calleeId: Long): Call {
        validationService.validateCallInitiation(callerId, calleeId)

        val caller = userRepository.findById(callerId)!!
        val callee = userRepository.findById(calleeId)!!
        val call = coreService.initiateCall(caller, callee)

        externalAdapter.apply {
            cacheCall(call)
            notifyIncomingCall(call)
            initializeBilling(call)
        }

        eventPublisher.publishCallInitiated(call)
        return call
    }
}
```

